import { use } from 'react';
import { Box, ElementProps, luminance } from '../../../core';
import { CheckIcon } from '../../Checkbox';
import { ColorSwatch } from '../../ColorSwatch';
import { ColorPickerContext } from '../ColorPicker.context';

export interface SwatchesProps extends ElementProps<'div'> {
  size?: string | number;
  data: string[];
  swatchesPerRow?: number;
  focusable?: boolean;
  value?: string;
  onChangeEnd?: (color: string) => void;
  setValue: (value: string) => void;
}

export function Swatches({
  className,
  datatype,
  setValue,
  onChangeEnd,
  size,
  focusable,
  data,
  swatchesPerRow,
  value,
  ...others
}: SwatchesProps) {
  const ctx = use(ColorPickerContext)!;

  const colors = data.map((color, index) => (
    <ColorSwatch
      {...ctx.getStyles('swatch')}
      unstyled={ctx.unstyled}
      component="button"
      type="button"
      color={color}
      key={index}
      radius="sm"
      onClick={() => {
        setValue(color);
        onChangeEnd?.(color);
      }}
      aria-label={color}
      tabIndex={focusable ? 0 : -1}
      data-swatch
    >
      {value === color && (
        <CheckIcon size="35%" color={luminance(color) < 0.5 ? 'white' : 'black'} />
      )}
    </ColorSwatch>
  ));

  return (
    <Box {...ctx.getStyles('swatches')} {...others}>
      {colors}
    </Box>
  );
}

Swatches.displayName = '@mantine/core/Swatches';
